BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Ischemic Heart Disease' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Ischemic Heart Disease', 'IHD spectrum, ACS patterns, NTG, reperfusion', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Ischemic Heart Disease (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Ischemic Heart Disease - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports IHD definition?', 'In this high-acuity chest pain scenario, which finding best supports IHD definition?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "Ischemic heart disease is a group of conditions caused by reduced blood flow to the myocardium."}, {"id": "c", "text": "This presentation is more consistent with LAD territory."}, {"id": "d", "text": "IHD always occurs without coronary flow limitation in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Ischemic heart disease is a group of conditions caused by reduced blood flow to the myocardium. Treat ischemic symptoms as perfusion mismatch until proven otherwise.', 'Ischemic Heart Disease - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects Etiology?', 'Which interpretation most accurately reflects Etiology?', '[{"id": "a", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "b", "text": "This presentation is more consistent with LCX territory."}, {"id": "c", "text": "Vasospasm is excluded in this note."}, {"id": "d", "text": "Different mechanisms change urgency and treatment strategy."}]'::jsonb, '["d"]'::jsonb, 'Correct because Major causes listed are atherosclerosis (most common), coronary vasospasm, and thrombosis. Different mechanisms change urgency and treatment strategy.', 'Ischemic Heart Disease - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with Clinical spectrum?', 'The nurse prioritizes interventions; which statement aligns with Clinical spectrum?', '[{"id": "a", "text": "The IHD spectrum is silent ischemia to stable angina, unstable angina, NSTEMI, and STEMI."}, {"id": "b", "text": "Stable angina is the most severe endpoint in this note."}, {"id": "c", "text": "STEMI is unrelated to IHD spectrum in this note."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because The IHD spectrum is silent ischemia to stable angina, unstable angina, NSTEMI, and STEMI. Progression across spectrum indicates rising acuity and intervention urgency.', 'Ischemic Heart Disease - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with Risk factors in this patient?', 'Which conclusion is most consistent with Risk factors in this patient?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "c", "text": "Family history does not matter in this note."}, {"id": "d", "text": "Risk-factor clustering should increase suspicion even with atypical presentations."}]'::jsonb, '["d"]'::jsonb, 'Correct because Risk factors include HTN, diabetes, hyperlipidemia, smoking, obesity, family history, and age thresholds male >45/female >55. Risk-factor clustering should increase suspicion even with atypical presentations.', 'Ischemic Heart Disease - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches LAD territory?', 'Which clinical judgment best matches LAD territory?', '[{"id": "a", "text": "LAD mainly supplies inferior wall in this note."}, {"id": "b", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "c", "text": "LAD supplies anterior wall and septum; occlusion causes anterior STEMI in V1–V4 and has high LV failure risk."}, {"id": "d", "text": "This presentation is more consistent with Unstable angina pattern."}]'::jsonb, '["c"]'::jsonb, 'Correct because LAD supplies anterior wall and septum; occlusion causes anterior STEMI in V1–V4 and has high LV failure risk. Anterior occlusion patterns require rapid reperfusion planning.', 'Ischemic Heart Disease - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports LCX territory?', 'In this high-acuity chest pain scenario, which finding best supports LCX territory?', '[{"id": "a", "text": "LCX always supplies AV node in this note."}, {"id": "b", "text": "Lead localization should guide likely vessel involvement."}, {"id": "c", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "d", "text": "LCX infarct localizes to V1–V4 in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because LCX supplies lateral wall (and SA node in some); occlusion causes lateral MI in I, aVL, V5–V6. Lead localization should guide likely vessel involvement.', 'Ischemic Heart Disease - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects RCA territory?', 'Which interpretation most accurately reflects RCA territory?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "AV block is rare with RCA MI in this note."}, {"id": "c", "text": "RCA infarcts primarily produce lateral lead changes in this note."}, {"id": "d", "text": "RCA supplies right ventricle, inferior wall, and AV node in about 80%; occlusion causes inferior STEMI in II, III, aVF with AV blocks common."}]'::jsonb, '["d"]'::jsonb, 'Correct because RCA supplies right ventricle, inferior wall, and AV node in about 80%; occlusion causes inferior STEMI in II, III, aVF with AV blocks common. Inferior MI with conduction changes should raise concern for RCA involvement.', 'Ischemic Heart Disease - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with Stable angina pattern?', 'The nurse prioritizes interventions; which statement aligns with Stable angina pattern?', '[{"id": "a", "text": "Stable angina does not respond to rest in this note."}, {"id": "b", "text": "Stable angina usually occurs at rest for >20 min in this note."}, {"id": "c", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "d", "text": "Predictable exertional pain suggests stable ischemia but still requires risk optimization."}]'::jsonb, '["d"]'::jsonb, 'Correct because Stable angina is predictable with exertion/stress, lasts less than 5 minutes, and resolves with rest. Predictable exertional pain suggests stable ischemia but still requires risk optimization.', 'Ischemic Heart Disease - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with Unstable angina pattern in this patient?', 'Which conclusion is most consistent with Unstable angina pattern in this patient?', '[{"id": "a", "text": "Unstable angina is always exertional and brief in this note."}, {"id": "b", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "c", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "d", "text": "Unstable angina is unpredictable, can occur at rest/minimal activity, often lasts >20 minutes, and does not resolve easily."}]'::jsonb, '["d"]'::jsonb, 'Correct because Unstable angina is unpredictable, can occur at rest/minimal activity, often lasts >20 minutes, and does not resolve easily. Treat unstable angina as high-risk ACS needing hospitalization.', 'Ischemic Heart Disease - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches Variant angina?', 'Which clinical judgment best matches Variant angina?', '[{"id": "a", "text": "Differentiate vasospastic episodes from fixed plaque obstruction patterns."}, {"id": "b", "text": "Variant angina has permanent ST depression in this note."}, {"id": "c", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because Prinzmetal angina is due to coronary vasospasm, occurs at rest/night, and shows transient ST elevation. Differentiate vasospastic episodes from fixed plaque obstruction patterns.', 'Ischemic Heart Disease - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports Stable angina treatment?', 'In this high-acuity chest pain scenario, which finding best supports Stable angina treatment?', '[{"id": "a", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "b", "text": "This presentation is more consistent with NSTEMI profile."}, {"id": "c", "text": "Stable angina treatment includes rest, SL nitroglycerin, beta-blockers, and aspirin."}, {"id": "d", "text": "Stable angina treatment excludes aspirin in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Stable angina treatment includes rest, SL nitroglycerin, beta-blockers, and aspirin. Early symptom control and anti-ischemic therapy prevent escalation.', 'Ischemic Heart Disease - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects Unstable angina treatment?', 'Which interpretation most accurately reflects Unstable angina treatment?', '[{"id": "a", "text": "This presentation is more consistent with NSTEMI timing."}, {"id": "b", "text": "No antithrombotic therapy is used in this note."}, {"id": "c", "text": "Escalate quickly because unstable angina may progress to infarction."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["c"]'::jsonb, 'Correct because Unstable angina management includes hospitalization, anticoagulation, dual antiplatelet therapy, and early PCI. Escalate quickly because unstable angina may progress to infarction.', 'Ischemic Heart Disease - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with STEMI pathophysiology?', 'The nurse prioritizes interventions; which statement aligns with STEMI pathophysiology?', '[{"id": "a", "text": "STEMI is partial occlusion without ST changes in this note."}, {"id": "b", "text": "STEMI is complete coronary occlusion with transmural infarction and ST elevation, with Q waves developing later."}, {"id": "c", "text": "STEMI is subendocardial only in this note."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["b"]'::jsonb, 'Correct because STEMI is complete coronary occlusion with transmural infarction and ST elevation, with Q waves developing later. Complete occlusion requires immediate reperfusion timeline focus.', 'Ischemic Heart Disease - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with STEMI reperfusion target in this patient?', 'Which conclusion is most consistent with STEMI reperfusion target in this patient?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "STEMI PCI can wait 24 hours in this note."}, {"id": "c", "text": "Time-to-reperfusion drives myocardial salvage and outcomes."}, {"id": "d", "text": "Thrombolytics are delayed until day 2 in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Primary PCI should occur within 90 minutes door-to-balloon; if unavailable, thrombolytics within 30 minutes are listed. Time-to-reperfusion drives myocardial salvage and outcomes.', 'Ischemic Heart Disease - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches NSTEMI profile?', 'Which clinical judgment best matches NSTEMI profile?', '[{"id": "a", "text": "NSTEMI is partial occlusion or severe vasospasm with subendocardial infarction, ST depression/T inversion, and elevated troponin without ST elevation."}, {"id": "b", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "c", "text": "This presentation is more consistent with NTG escalation."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because NSTEMI is partial occlusion or severe vasospasm with subendocardial infarction, ST depression/T inversion, and elevated troponin without ST elevation. No ST elevation does not mean low risk; troponin-positive NSTEMI still needs intervention.', 'Ischemic Heart Disease - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports NSTEMI timing?', 'In this high-acuity chest pain scenario, which finding best supports NSTEMI timing?', '[{"id": "a", "text": "Schedule timely invasive strategy while stabilizing medically."}, {"id": "b", "text": "NSTEMI is treated with discharge only in this note."}, {"id": "c", "text": "This presentation is more consistent with NTG storage."}, {"id": "d", "text": "Serial evaluation can be deferred to outpatient follow-up."}]'::jsonb, '["a"]'::jsonb, 'Correct because NSTEMI treatment includes anticoagulation + dual antiplatelet and early PCI within 24–72 hours. Schedule timely invasive strategy while stabilizing medically.', 'Ischemic Heart Disease - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects NTG BP safety?', 'Which interpretation most accurately reflects NTG BP safety?', '[{"id": "a", "text": "Before SL nitroglycerin, check BP and hold if systolic is <90 mmHg; patient should sit down."}, {"id": "b", "text": "Standing position is preferred for NTG in this note."}, {"id": "c", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "d", "text": "Serial evaluation can be deferred to outpatient follow-up."}]'::jsonb, '["a"]'::jsonb, 'Correct because Before SL nitroglycerin, check BP and hold if systolic is <90 mmHg; patient should sit down. Prevent NTG-related hypotension and syncope during administration.', 'Ischemic Heart Disease - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with NTG dosing sequence?', 'The nurse prioritizes interventions; which statement aligns with NTG dosing sequence?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "c", "text": "Unlimited NTG doses are allowed in this note."}, {"id": "d", "text": "Follow timing strictly and escalate if pain persists."}]'::jsonb, '["d"]'::jsonb, 'Correct because SL NTG is given every 5 minutes up to 3 doses for persistent angina. Follow timing strictly and escalate if pain persists.', 'Ischemic Heart Disease - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with NTG escalation in this patient?', 'Which conclusion is most consistent with NTG escalation in this patient?', '[{"id": "a", "text": "Pain persistence after 3 doses is low concern in this note."}, {"id": "b", "text": "Wait several hours after 3 doses before escalation in this note."}, {"id": "c", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "d", "text": "If pain remains after 3 doses, activate emergency response (call 911/STEMI protocol)."}]'::jsonb, '["d"]'::jsonb, 'Correct because If pain remains after 3 doses, activate emergency response (call 911/STEMI protocol). Unrelieved pain after protocol doses signals possible infarction requiring immediate action.', 'Ischemic Heart Disease - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches NTG storage?', 'Which clinical judgment best matches NTG storage?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "c", "text": "Potency is unaffected by storage in this note."}, {"id": "d", "text": "Proper storage preserves potency for emergency symptom control."}]'::jsonb, '["d"]'::jsonb, 'Correct because NTG should be kept in original dark glass bottle, room temperature, replaced every 6 months or when tongue burning sensation disappears. Proper storage preserves potency for emergency symptom control.', 'Ischemic Heart Disease - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports MONA oxygen rule?', 'In this high-acuity chest pain scenario, which finding best supports MONA oxygen rule?', '[{"id": "a", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "b", "text": "Oxygen in MONA is indicated only if SpO2 is below 94% to avoid hyperoxia."}, {"id": "c", "text": "This presentation is more consistent with Troponin T kinetics."}, {"id": "d", "text": "Serial evaluation can be deferred to outpatient follow-up."}]'::jsonb, '["b"]'::jsonb, 'Correct because Oxygen in MONA is indicated only if SpO2 is below 94% to avoid hyperoxia. Use oxygen selectively rather than automatically in all chest pain cases.', 'Ischemic Heart Disease - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects MONA aspirin detail?', 'Which interpretation most accurately reflects MONA aspirin detail?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "Immediate antiplatelet therapy is a frontline mortality-reduction step."}, {"id": "c", "text": "Aspirin should be swallowed whole and delayed in this note."}, {"id": "d", "text": "This presentation is more consistent with NCLEX first action."}]'::jsonb, '["b"]'::jsonb, 'Correct because Aspirin 325 mg is given immediately and chewed. Immediate antiplatelet therapy is a frontline mortality-reduction step.', 'Ischemic Heart Disease - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with Additional ACS medications?', 'The nurse prioritizes interventions; which statement aligns with Additional ACS medications?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "Statins are not part of post-MI care in this note."}, {"id": "c", "text": "Additional therapies listed are DAPT (clopidogrel + aspirin), heparin, beta-blocker, ACE inhibitor, and statin."}, {"id": "d", "text": "Heparin is avoided in all ACS in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Additional therapies listed are DAPT (clopidogrel + aspirin), heparin, beta-blocker, ACE inhibitor, and statin. Combine antithrombotic and cardioprotective therapies to reduce reinfarction and mortality.', 'Ischemic Heart Disease - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with Troponin I kinetics in this patient?', 'Which conclusion is most consistent with Troponin I kinetics in this patient?', '[{"id": "a", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "b", "text": "Use timing to interpret serial markers accurately."}, {"id": "c", "text": "Troponin I normal is >5 ng/mL in this note."}, {"id": "d", "text": "Serial evaluation can be deferred to outpatient follow-up."}]'::jsonb, '["b"]'::jsonb, 'Correct because Troponin I normal is <0.04 ng/mL, rises 3–6 hrs, peaks 12–24 hrs, and remains elevated 7–10 days. Use timing to interpret serial markers accurately.', 'Ischemic Heart Disease - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches Troponin T kinetics?', 'Which clinical judgment best matches Troponin T kinetics?', '[{"id": "a", "text": "Troponin T normal is <0.01 ng/mL, rises 3–6 hrs, peaks 12–24 hrs, and can stay elevated 10–14 days."}, {"id": "b", "text": "This presentation is more consistent with Clinical spectrum."}, {"id": "c", "text": "Troponin T is not used in MI workup in this note."}, {"id": "d", "text": "Troponin T returns to baseline in 2 hours in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Troponin T normal is <0.01 ng/mL, rises 3–6 hrs, peaks 12–24 hrs, and can stay elevated 10–14 days. Longer elevation duration affects interpretation in late presenters.', 'Ischemic Heart Disease - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports NCLEX first action?', 'In this high-acuity chest pain scenario, which finding best supports NCLEX first action?', '[{"id": "a", "text": "This presentation is more consistent with Risk factors."}, {"id": "b", "text": "Immediate rhythm/injury assessment plus antiplatelet action should not be delayed."}, {"id": "c", "text": "NTG potency check precedes all acute actions in this note."}, {"id": "d", "text": "Delay EKG until after serial enzymes in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because For chest pain, first action is 12-lead EKG and provider notification; aspirin is immediate and chewed. Immediate rhythm/injury assessment plus antiplatelet action should not be delayed.', 'Ischemic Heart Disease - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects IHD definition?', 'Which interpretation most accurately reflects IHD definition?', '[{"id": "a", "text": "This presentation is more consistent with LAD territory."}, {"id": "b", "text": "IHD is primarily pericardial inflammation in this note."}, {"id": "c", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "d", "text": "Ischemic heart disease is a group of conditions caused by reduced blood flow to the myocardium."}]'::jsonb, '["d"]'::jsonb, 'Correct because Ischemic heart disease is a group of conditions caused by reduced blood flow to the myocardium. Treat ischemic symptoms as perfusion mismatch until proven otherwise.', 'Ischemic Heart Disease - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with Etiology?', 'The nurse prioritizes interventions; which statement aligns with Etiology?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "c", "text": "Vasospasm is excluded in this note."}, {"id": "d", "text": "Different mechanisms change urgency and treatment strategy."}]'::jsonb, '["d"]'::jsonb, 'Correct because Major causes listed are atherosclerosis (most common), coronary vasospasm, and thrombosis. Different mechanisms change urgency and treatment strategy.', 'Ischemic Heart Disease - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with Clinical spectrum in this patient?', 'Which conclusion is most consistent with Clinical spectrum in this patient?', '[{"id": "a", "text": "The IHD spectrum is silent ischemia to stable angina, unstable angina, NSTEMI, and STEMI."}, {"id": "b", "text": "This presentation is more consistent with RCA territory."}, {"id": "c", "text": "STEMI is unrelated to IHD spectrum in this note."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because The IHD spectrum is silent ischemia to stable angina, unstable angina, NSTEMI, and STEMI. Progression across spectrum indicates rising acuity and intervention urgency.', 'Ischemic Heart Disease - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches Risk factors?', 'Which clinical judgment best matches Risk factors?', '[{"id": "a", "text": "Risk-factor clustering should increase suspicion even with atypical presentations."}, {"id": "b", "text": "Family history does not matter in this note."}, {"id": "c", "text": "This presentation is more consistent with Stable angina pattern."}, {"id": "d", "text": "Serial evaluation can be deferred to outpatient follow-up."}]'::jsonb, '["a"]'::jsonb, 'Correct because Risk factors include HTN, diabetes, hyperlipidemia, smoking, obesity, family history, and age thresholds male >45/female >55. Risk-factor clustering should increase suspicion even with atypical presentations.', 'Ischemic Heart Disease - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports LAD territory?', 'In this high-acuity chest pain scenario, which finding best supports LAD territory?', '[{"id": "a", "text": "LAD infarct primarily appears in II, III, aVF in this note."}, {"id": "b", "text": "LAD supplies anterior wall and septum; occlusion causes anterior STEMI in V1–V4 and has high LV failure risk."}, {"id": "c", "text": "LAD mainly supplies inferior wall in this note."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["b"]'::jsonb, 'Correct because LAD supplies anterior wall and septum; occlusion causes anterior STEMI in V1–V4 and has high LV failure risk. Anterior occlusion patterns require rapid reperfusion planning.', 'Ischemic Heart Disease - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects LCX territory?', 'Which interpretation most accurately reflects LCX territory?', '[{"id": "a", "text": "LCX infarct localizes to V1–V4 in this note."}, {"id": "b", "text": "Lead localization should guide likely vessel involvement."}, {"id": "c", "text": "This presentation is more consistent with Variant angina."}, {"id": "d", "text": "Serial evaluation can be deferred to outpatient follow-up."}]'::jsonb, '["b"]'::jsonb, 'Correct because LCX supplies lateral wall (and SA node in some); occlusion causes lateral MI in I, aVL, V5–V6. Lead localization should guide likely vessel involvement.', 'Ischemic Heart Disease - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with RCA territory?', 'The nurse prioritizes interventions; which statement aligns with RCA territory?', '[{"id": "a", "text": "RCA infarcts primarily produce lateral lead changes in this note."}, {"id": "b", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "c", "text": "RCA supplies right ventricle, inferior wall, and AV node in about 80%; occlusion causes inferior STEMI in II, III, aVF with AV blocks common."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["c"]'::jsonb, 'Correct because RCA supplies right ventricle, inferior wall, and AV node in about 80%; occlusion causes inferior STEMI in II, III, aVF with AV blocks common. Inferior MI with conduction changes should raise concern for RCA involvement.', 'Ischemic Heart Disease - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with Stable angina pattern in this patient?', 'Which conclusion is most consistent with Stable angina pattern in this patient?', '[{"id": "a", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "b", "text": "Stable angina usually occurs at rest for >20 min in this note."}, {"id": "c", "text": "Predictable exertional pain suggests stable ischemia but still requires risk optimization."}, {"id": "d", "text": "This presentation is more consistent with Unstable angina treatment."}]'::jsonb, '["c"]'::jsonb, 'Correct because Stable angina is predictable with exertion/stress, lasts less than 5 minutes, and resolves with rest. Predictable exertional pain suggests stable ischemia but still requires risk optimization.', 'Ischemic Heart Disease - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches Unstable angina pattern?', 'Which clinical judgment best matches Unstable angina pattern?', '[{"id": "a", "text": "Unstable angina is unpredictable, can occur at rest/minimal activity, often lasts >20 minutes, and does not resolve easily."}, {"id": "b", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "c", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "d", "text": "Unstable angina is always exertional and brief in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Unstable angina is unpredictable, can occur at rest/minimal activity, often lasts >20 minutes, and does not resolve easily. Treat unstable angina as high-risk ACS needing hospitalization.', 'Ischemic Heart Disease - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports Variant angina?', 'In this high-acuity chest pain scenario, which finding best supports Variant angina?', '[{"id": "a", "text": "Beta-blockers are preferred first-line in this note."}, {"id": "b", "text": "Variant angina has permanent ST depression in this note."}, {"id": "c", "text": "Differentiate vasospastic episodes from fixed plaque obstruction patterns."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["c"]'::jsonb, 'Correct because Prinzmetal angina is due to coronary vasospasm, occurs at rest/night, and shows transient ST elevation. Differentiate vasospastic episodes from fixed plaque obstruction patterns.', 'Ischemic Heart Disease - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects Stable angina treatment?', 'Which interpretation most accurately reflects Stable angina treatment?', '[{"id": "a", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "b", "text": "Stable angina treatment excludes aspirin in this note."}, {"id": "c", "text": "Stable angina treatment includes rest, SL nitroglycerin, beta-blockers, and aspirin."}, {"id": "d", "text": "Serial evaluation can be deferred to outpatient follow-up."}]'::jsonb, '["c"]'::jsonb, 'Correct because Stable angina treatment includes rest, SL nitroglycerin, beta-blockers, and aspirin. Early symptom control and anti-ischemic therapy prevent escalation.', 'Ischemic Heart Disease - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with Unstable angina treatment?', 'The nurse prioritizes interventions; which statement aligns with Unstable angina treatment?', '[{"id": "a", "text": "Escalate quickly because unstable angina may progress to infarction."}, {"id": "b", "text": "Unstable angina should be managed only with PRN NTG at home in this note."}, {"id": "c", "text": "This presentation is more consistent with NSTEMI timing."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because Unstable angina management includes hospitalization, anticoagulation, dual antiplatelet therapy, and early PCI. Escalate quickly because unstable angina may progress to infarction.', 'Ischemic Heart Disease - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with STEMI pathophysiology in this patient?', 'Which conclusion is most consistent with STEMI pathophysiology in this patient?', '[{"id": "a", "text": "STEMI is complete coronary occlusion with transmural infarction and ST elevation, with Q waves developing later."}, {"id": "b", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "c", "text": "STEMI is subendocardial only in this note."}, {"id": "d", "text": "Serial evaluation can be deferred to outpatient follow-up."}]'::jsonb, '["a"]'::jsonb, 'Correct because STEMI is complete coronary occlusion with transmural infarction and ST elevation, with Q waves developing later. Complete occlusion requires immediate reperfusion timeline focus.', 'Ischemic Heart Disease - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches STEMI reperfusion target?', 'Which clinical judgment best matches STEMI reperfusion target?', '[{"id": "a", "text": "Time-to-reperfusion drives myocardial salvage and outcomes."}, {"id": "b", "text": "Thrombolytics are delayed until day 2 in this note."}, {"id": "c", "text": "This presentation is more consistent with NTG dosing sequence."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because Primary PCI should occur within 90 minutes door-to-balloon; if unavailable, thrombolytics within 30 minutes are listed. Time-to-reperfusion drives myocardial salvage and outcomes.', 'Ischemic Heart Disease - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports NSTEMI profile?', 'In this high-acuity chest pain scenario, which finding best supports NSTEMI profile?', '[{"id": "a", "text": "NSTEMI troponin remains normal in this note."}, {"id": "b", "text": "NSTEMI is partial occlusion or severe vasospasm with subendocardial infarction, ST depression/T inversion, and elevated troponin without ST elevation."}, {"id": "c", "text": "NSTEMI requires ST elevation to diagnose in this note."}, {"id": "d", "text": "This presentation is more consistent with NTG escalation."}]'::jsonb, '["b"]'::jsonb, 'Correct because NSTEMI is partial occlusion or severe vasospasm with subendocardial infarction, ST depression/T inversion, and elevated troponin without ST elevation. No ST elevation does not mean low risk; troponin-positive NSTEMI still needs intervention.', 'Ischemic Heart Disease - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects NSTEMI timing?', 'Which interpretation most accurately reflects NSTEMI timing?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "Schedule timely invasive strategy while stabilizing medically."}, {"id": "c", "text": "NSTEMI never receives PCI in this note."}, {"id": "d", "text": "NSTEMI is treated with discharge only in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because NSTEMI treatment includes anticoagulation + dual antiplatelet and early PCI within 24–72 hours. Schedule timely invasive strategy while stabilizing medically.', 'Ischemic Heart Disease - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with NTG BP safety?', 'The nurse prioritizes interventions; which statement aligns with NTG BP safety?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "NTG should be given regardless of BP in this note."}, {"id": "c", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "d", "text": "Before SL nitroglycerin, check BP and hold if systolic is <90 mmHg; patient should sit down."}]'::jsonb, '["d"]'::jsonb, 'Correct because Before SL nitroglycerin, check BP and hold if systolic is <90 mmHg; patient should sit down. Prevent NTG-related hypotension and syncope during administration.', 'Ischemic Heart Disease - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with NTG dosing sequence in this patient?', 'Which conclusion is most consistent with NTG dosing sequence in this patient?', '[{"id": "a", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "b", "text": "Follow timing strictly and escalate if pain persists."}, {"id": "c", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "d", "text": "This presentation is more consistent with MONA aspirin detail."}]'::jsonb, '["b"]'::jsonb, 'Correct because SL NTG is given every 5 minutes up to 3 doses for persistent angina. Follow timing strictly and escalate if pain persists.', 'Ischemic Heart Disease - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches NTG escalation?', 'Which clinical judgment best matches NTG escalation?', '[{"id": "a", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "b", "text": "If pain remains after 3 doses, activate emergency response (call 911/STEMI protocol)."}, {"id": "c", "text": "Pain persistence after 3 doses is low concern in this note."}, {"id": "d", "text": "Wait several hours after 3 doses before escalation in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because If pain remains after 3 doses, activate emergency response (call 911/STEMI protocol). Unrelieved pain after protocol doses signals possible infarction requiring immediate action.', 'Ischemic Heart Disease - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In this high-acuity chest pain scenario, which finding best supports NTG storage?', 'In this high-acuity chest pain scenario, which finding best supports NTG storage?', '[{"id": "a", "text": "Proper storage preserves potency for emergency symptom control."}, {"id": "b", "text": "This presentation is more consistent with Troponin I kinetics."}, {"id": "c", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "d", "text": "Emergency escalation is unnecessary because these findings are low risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because NTG should be kept in original dark glass bottle, room temperature, replaced every 6 months or when tongue burning sensation disappears. Proper storage preserves potency for emergency symptom control.', 'Ischemic Heart Disease - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which interpretation most accurately reflects MONA oxygen rule?', 'Which interpretation most accurately reflects MONA oxygen rule?', '[{"id": "a", "text": "Oxygen in MONA is indicated only if SpO2 is below 94% to avoid hyperoxia."}, {"id": "b", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "c", "text": "All chest pain patients need routine oxygen regardless of saturation in this note."}, {"id": "d", "text": "This presentation is more consistent with Troponin T kinetics."}]'::jsonb, '["a"]'::jsonb, 'Correct because Oxygen in MONA is indicated only if SpO2 is below 94% to avoid hyperoxia. Use oxygen selectively rather than automatically in all chest pain cases.', 'Ischemic Heart Disease - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse prioritizes interventions; which statement aligns with MONA aspirin detail?', 'The nurse prioritizes interventions; which statement aligns with MONA aspirin detail?', '[{"id": "a", "text": "This presentation is more consistent with NCLEX first action."}, {"id": "b", "text": "Immediate antiplatelet therapy is a frontline mortality-reduction step."}, {"id": "c", "text": "Aspirin is contraindicated in all ACS cases in this note."}, {"id": "d", "text": "Aspirin should be swallowed whole and delayed in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Aspirin 325 mg is given immediately and chewed. Immediate antiplatelet therapy is a frontline mortality-reduction step.', 'Ischemic Heart Disease - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion is most consistent with Additional ACS medications in this patient?', 'Which conclusion is most consistent with Additional ACS medications in this patient?', '[{"id": "a", "text": "Additional therapies listed are DAPT (clopidogrel + aspirin), heparin, beta-blocker, ACE inhibitor, and statin."}, {"id": "b", "text": "Emergency escalation is unnecessary because these findings are low risk."}, {"id": "c", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "d", "text": "This presentation is more consistent with IHD definition."}]'::jsonb, '["a"]'::jsonb, 'Correct because Additional therapies listed are DAPT (clopidogrel + aspirin), heparin, beta-blocker, ACE inhibitor, and statin. Combine antithrombotic and cardioprotective therapies to reduce reinfarction and mortality.', 'Ischemic Heart Disease - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment best matches Troponin I kinetics?', 'Which clinical judgment best matches Troponin I kinetics?', '[{"id": "a", "text": "Troponin I normalizes within 12 hours in this note."}, {"id": "b", "text": "Serial evaluation can be deferred to outpatient follow-up."}, {"id": "c", "text": "Use timing to interpret serial markers accurately."}, {"id": "d", "text": "Troponin I normal is >5 ng/mL in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Troponin I normal is <0.04 ng/mL, rises 3–6 hrs, peaks 12–24 hrs, and remains elevated 7–10 days. Use timing to interpret serial markers accurately.', 'Ischemic Heart Disease - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for IHD definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for IHD definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "IHD is a spectrum rather than one single condition."}, {"id": "b", "text": "IHD involves reduced myocardial perfusion."}, {"id": "c", "text": "Myocardial oxygen supply-demand mismatch is central."}, {"id": "d", "text": "IHD always occurs without coronary flow limitation in this note."}, {"id": "e", "text": "IHD is primarily pericardial inflammation in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Ischemic heart disease is a group of conditions caused by reduced blood flow to the myocardium.', 'Ischemic Heart Disease - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and Etiology, which statements are correct? (Select all that apply)', 'For suspected ACS and Etiology, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Coronary vasospasm is listed as a cause."}, {"id": "b", "text": "Atherosclerosis is the most common cause listed."}, {"id": "c", "text": "Thrombosis is listed as a cause."}, {"id": "d", "text": "Only congenital defects cause IHD in this note."}, {"id": "e", "text": "Vasospasm is excluded in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Major causes listed are atherosclerosis (most common), coronary vasospasm, and thrombosis.', 'Ischemic Heart Disease - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Clinical spectrum? (Select all that apply)', 'During reassessment, which observations support Clinical spectrum? (Select all that apply)', '[{"id": "a", "text": "Unstable angina precedes infarction stages in spectrum."}, {"id": "b", "text": "STEMI is unrelated to IHD spectrum in this note."}, {"id": "c", "text": "NSTEMI and STEMI are part of IHD spectrum."}, {"id": "d", "text": "Stable angina is the most severe endpoint in this note."}, {"id": "e", "text": "Silent ischemia can occur in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: The IHD spectrum is silent ischemia to stable angina, unstable angina, NSTEMI, and STEMI.', 'Ischemic Heart Disease - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Risk factors. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Risk factors. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Family history does not matter in this note."}, {"id": "b", "text": "Age thresholds are listed for men and women."}, {"id": "c", "text": "Only age under 30 is listed as risk in this note."}, {"id": "d", "text": "Smoking and obesity are listed risk factors."}, {"id": "e", "text": "Hypertension and diabetes are listed risk factors."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Risk factors include HTN, diabetes, hyperlipidemia, smoking, obesity, family history, and age thresholds male >45/female >55.', 'Ischemic Heart Disease - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with LAD territory from this note? (Select all that apply)', 'Which clues are consistent with LAD territory from this note? (Select all that apply)', '[{"id": "a", "text": "LAD occlusion maps to V1–V4 anterior STEMI."}, {"id": "b", "text": "LAD infarct primarily appears in II, III, aVF in this note."}, {"id": "c", "text": "Anterior territory loss risks LV failure."}, {"id": "d", "text": "LAD is called widow maker in this note."}, {"id": "e", "text": "LAD mainly supplies inferior wall in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: LAD supplies anterior wall and septum; occlusion causes anterior STEMI in V1–V4 and has high LV failure risk.', 'Ischemic Heart Disease - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for LCX territory. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for LCX territory. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "LCX always supplies AV node in this note."}, {"id": "b", "text": "Lateral MI leads include I, aVL, V5, V6 for LCX."}, {"id": "c", "text": "LCX infarct localizes to V1–V4 in this note."}, {"id": "d", "text": "LCX is often non-dominant in this note."}, {"id": "e", "text": "LCX can supply SA node in some patients."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: LCX supplies lateral wall (and SA node in some); occlusion causes lateral MI in I, aVL, V5–V6.', 'Ischemic Heart Disease - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and RCA territory, which statements are correct? (Select all that apply)', 'For suspected ACS and RCA territory, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "RCA supplies right ventricle/inferior wall in this note."}, {"id": "b", "text": "AV blocks are common with RCA MI in this note."}, {"id": "c", "text": "RCA infarcts primarily produce lateral lead changes in this note."}, {"id": "d", "text": "AV block is rare with RCA MI in this note."}, {"id": "e", "text": "Inferior STEMI leads are II, III, aVF for RCA."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: RCA supplies right ventricle, inferior wall, and AV node in about 80%; occlusion causes inferior STEMI in II, III, aVF with AV blocks common.', 'Ischemic Heart Disease - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Stable angina pattern? (Select all that apply)', 'During reassessment, which observations support Stable angina pattern? (Select all that apply)', '[{"id": "a", "text": "Stable angina usually occurs at rest for >20 min in this note."}, {"id": "b", "text": "Stable angina is predictable in this note."}, {"id": "c", "text": "Stable angina does not respond to rest in this note."}, {"id": "d", "text": "Rest commonly relieves symptoms."}, {"id": "e", "text": "Duration is usually under 5 minutes."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Stable angina is predictable with exertion/stress, lasts less than 5 minutes, and resolves with rest.', 'Ischemic Heart Disease - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Unstable angina pattern. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Unstable angina pattern. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Unstable angina is managed only with home rest in this note."}, {"id": "b", "text": "Duration over 20 minutes is noted."}, {"id": "c", "text": "Unstable angina is always exertional and brief in this note."}, {"id": "d", "text": "Early PCI strategy is listed for unstable angina."}, {"id": "e", "text": "Unstable angina may occur at rest."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Unstable angina is unpredictable, can occur at rest/minimal activity, often lasts >20 minutes, and does not resolve easily.', 'Ischemic Heart Disease - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Variant angina from this note? (Select all that apply)', 'Which clues are consistent with Variant angina from this note? (Select all that apply)', '[{"id": "a", "text": "Variant angina occurs at rest/night in this note."}, {"id": "b", "text": "Transient ST elevation is described."}, {"id": "c", "text": "Variant angina has permanent ST depression in this note."}, {"id": "d", "text": "Beta-blockers are preferred first-line in this note."}, {"id": "e", "text": "CCBs and nitrates are listed therapy."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Prinzmetal angina is due to coronary vasospasm, occurs at rest/night, and shows transient ST elevation.', 'Ischemic Heart Disease - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for Stable angina treatment. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for Stable angina treatment. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "SL nitroglycerin is listed for stable episodes."}, {"id": "b", "text": "Thrombolytics are routine first-line for stable angina in this note."}, {"id": "c", "text": "Rest is first response in stable episodes."}, {"id": "d", "text": "Stable angina treatment excludes aspirin in this note."}, {"id": "e", "text": "Beta-blockers and aspirin are listed in management."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Stable angina treatment includes rest, SL nitroglycerin, beta-blockers, and aspirin.', 'Ischemic Heart Disease - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and Unstable angina treatment, which statements are correct? (Select all that apply)', 'For suspected ACS and Unstable angina treatment, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "No antithrombotic therapy is used in this note."}, {"id": "b", "text": "Dual antiplatelet and anticoagulation are listed."}, {"id": "c", "text": "Early PCI is part of management."}, {"id": "d", "text": "Unstable angina should be managed only with PRN NTG at home in this note."}, {"id": "e", "text": "Hospitalization is indicated in unstable angina."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Unstable angina management includes hospitalization, anticoagulation, dual antiplatelet therapy, and early PCI.', 'Ischemic Heart Disease - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support STEMI pathophysiology? (Select all that apply)', 'During reassessment, which observations support STEMI pathophysiology? (Select all that apply)', '[{"id": "a", "text": "STEMI is partial occlusion without ST changes in this note."}, {"id": "b", "text": "STEMI is complete occlusion in this note."}, {"id": "c", "text": "ST elevation is present in STEMI."}, {"id": "d", "text": "Q waves may appear later in STEMI."}, {"id": "e", "text": "STEMI is subendocardial only in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: STEMI is complete coronary occlusion with transmural infarction and ST elevation, with Q waves developing later.', 'Ischemic Heart Disease - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around STEMI reperfusion target. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around STEMI reperfusion target. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Door-to-balloon target is 90 minutes in this note."}, {"id": "b", "text": "Reperfusion timing is urgent in STEMI."}, {"id": "c", "text": "STEMI PCI can wait 24 hours in this note."}, {"id": "d", "text": "Thrombolytics are delayed until day 2 in this note."}, {"id": "e", "text": "Thrombolytic target is 30 minutes if PCI unavailable."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Primary PCI should occur within 90 minutes door-to-balloon; if unavailable, thrombolytics within 30 minutes are listed.', 'Ischemic Heart Disease - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with NSTEMI profile from this note? (Select all that apply)', 'Which clues are consistent with NSTEMI profile from this note? (Select all that apply)', '[{"id": "a", "text": "Troponin is elevated in NSTEMI."}, {"id": "b", "text": "NSTEMI requires ST elevation to diagnose in this note."}, {"id": "c", "text": "NSTEMI troponin remains normal in this note."}, {"id": "d", "text": "NSTEMI has no ST elevation in this note."}, {"id": "e", "text": "ST depression/T-wave inversion can occur."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: NSTEMI is partial occlusion or severe vasospasm with subendocardial infarction, ST depression/T inversion, and elevated troponin without ST elevation.', 'Ischemic Heart Disease - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for NSTEMI timing. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for NSTEMI timing. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "NSTEMI never receives PCI in this note."}, {"id": "b", "text": "NSTEMI is treated with discharge only in this note."}, {"id": "c", "text": "Early PCI window is 24–72 hours in this note."}, {"id": "d", "text": "Dual antiplatelet is listed in NSTEMI care."}, {"id": "e", "text": "Anticoagulation is listed in NSTEMI care."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: NSTEMI treatment includes anticoagulation + dual antiplatelet and early PCI within 24–72 hours.', 'Ischemic Heart Disease - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and NTG BP safety, which statements are correct? (Select all that apply)', 'For suspected ACS and NTG BP safety, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Standing position is preferred for NTG in this note."}, {"id": "b", "text": "Hold NTG if systolic BP is under 90."}, {"id": "c", "text": "BP check is step 1 in protocol."}, {"id": "d", "text": "NTG should be given regardless of BP in this note."}, {"id": "e", "text": "Patient should be seated before dosing."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Before SL nitroglycerin, check BP and hold if systolic is <90 mmHg; patient should sit down.', 'Ischemic Heart Disease - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support NTG dosing sequence? (Select all that apply)', 'During reassessment, which observations support NTG dosing sequence? (Select all that apply)', '[{"id": "a", "text": "Dosing interval is 5 minutes in this note."}, {"id": "b", "text": "Maximum is 3 doses in protocol."}, {"id": "c", "text": "Persistent pain after sequential doses needs escalation."}, {"id": "d", "text": "NTG should be repeated every 30 seconds in this note."}, {"id": "e", "text": "Unlimited NTG doses are allowed in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: SL NTG is given every 5 minutes up to 3 doses for persistent angina.', 'Ischemic Heart Disease - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around NTG escalation. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around NTG escalation. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Pain persistence after 3 doses is low concern in this note."}, {"id": "b", "text": "Escalation should not be delayed."}, {"id": "c", "text": "Persistent pain indicates possible acute MI."}, {"id": "d", "text": "Wait several hours after 3 doses before escalation in this note."}, {"id": "e", "text": "Emergency activation follows 3 unrelieved doses."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: If pain remains after 3 doses, activate emergency response (call 911/STEMI protocol).', 'Ischemic Heart Disease - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with NTG storage from this note? (Select all that apply)', 'Which clues are consistent with NTG storage from this note? (Select all that apply)', '[{"id": "a", "text": "NTG should be stored in clear pill organizers in this note."}, {"id": "b", "text": "Dark glass bottle storage is specified."}, {"id": "c", "text": "Potency is unaffected by storage in this note."}, {"id": "d", "text": "Loss of tongue burning suggests potency loss."}, {"id": "e", "text": "Replace every 6 months is listed."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: NTG should be kept in original dark glass bottle, room temperature, replaced every 6 months or when tongue burning sensation disappears.', 'Ischemic Heart Disease - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for MONA oxygen rule. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for MONA oxygen rule. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Oxygen is never used in ACS in this note."}, {"id": "b", "text": "Oxygen is conditional on SpO2 <94% in this note."}, {"id": "c", "text": "All chest pain patients need routine oxygen regardless of saturation in this note."}, {"id": "d", "text": "Oxygen is part of MONA with indication limits."}, {"id": "e", "text": "Hyperoxia avoidance is emphasized."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Oxygen in MONA is indicated only if SpO2 is below 94% to avoid hyperoxia.', 'Ischemic Heart Disease - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and MONA aspirin detail, which statements are correct? (Select all that apply)', 'For suspected ACS and MONA aspirin detail, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Aspirin is part of first-line acute MI response."}, {"id": "b", "text": "Aspirin should be swallowed whole and delayed in this note."}, {"id": "c", "text": "Aspirin is contraindicated in all ACS cases in this note."}, {"id": "d", "text": "Aspirin should be chewed immediately."}, {"id": "e", "text": "Dose listed is 325 mg."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Aspirin 325 mg is given immediately and chewed.', 'Ischemic Heart Disease - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Additional ACS medications? (Select all that apply)', 'During reassessment, which observations support Additional ACS medications? (Select all that apply)', '[{"id": "a", "text": "Heparin is avoided in all ACS in this note."}, {"id": "b", "text": "ACE inhibitor and statin are listed post-MI supports."}, {"id": "c", "text": "Statins are not part of post-MI care in this note."}, {"id": "d", "text": "Clopidogrel + aspirin is listed."}, {"id": "e", "text": "Heparin is listed for anticoagulation."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Additional therapies listed are DAPT (clopidogrel + aspirin), heparin, beta-blocker, ACE inhibitor, and statin.', 'Ischemic Heart Disease - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Troponin I kinetics. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Troponin I kinetics. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Troponin I normal is >5 ng/mL in this note."}, {"id": "b", "text": "Troponin I rises at 3–6 hours."}, {"id": "c", "text": "Troponin I peaks around 12–24 hours."}, {"id": "d", "text": "Troponin I may remain elevated for 7–10 days."}, {"id": "e", "text": "Troponin I normalizes within 12 hours in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Troponin I normal is <0.04 ng/mL, rises 3–6 hrs, peaks 12–24 hrs, and remains elevated 7–10 days.', 'Ischemic Heart Disease - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Troponin T kinetics from this note? (Select all that apply)', 'Which clues are consistent with Troponin T kinetics from this note? (Select all that apply)', '[{"id": "a", "text": "Troponin T normal threshold is <0.01 ng/mL."}, {"id": "b", "text": "Troponin T can stay elevated up to 10–14 days."}, {"id": "c", "text": "Troponin T returns to baseline in 2 hours in this note."}, {"id": "d", "text": "Rise and peak timing mirror early troponin response windows."}, {"id": "e", "text": "Troponin T is not used in MI workup in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Troponin T normal is <0.01 ng/mL, rises 3–6 hrs, peaks 12–24 hrs, and can stay elevated 10–14 days.', 'Ischemic Heart Disease - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for NCLEX first action. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for NCLEX first action. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Chewed aspirin is immediate in NCLEX tip."}, {"id": "b", "text": "12-lead EKG within 10 minutes is listed."}, {"id": "c", "text": "Delay EKG until after serial enzymes in this note."}, {"id": "d", "text": "Provider notification is part of first action."}, {"id": "e", "text": "NTG potency check precedes all acute actions in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: For chest pain, first action is 12-lead EKG and provider notification; aspirin is immediate and chewed.', 'Ischemic Heart Disease - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and IHD definition, which statements are correct? (Select all that apply)', 'For suspected ACS and IHD definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "IHD always occurs without coronary flow limitation in this note."}, {"id": "b", "text": "IHD involves reduced myocardial perfusion."}, {"id": "c", "text": "IHD is primarily pericardial inflammation in this note."}, {"id": "d", "text": "Myocardial oxygen supply-demand mismatch is central."}, {"id": "e", "text": "IHD is a spectrum rather than one single condition."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Ischemic heart disease is a group of conditions caused by reduced blood flow to the myocardium.', 'Ischemic Heart Disease - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Etiology? (Select all that apply)', 'During reassessment, which observations support Etiology? (Select all that apply)', '[{"id": "a", "text": "Thrombosis is listed as a cause."}, {"id": "b", "text": "Coronary vasospasm is listed as a cause."}, {"id": "c", "text": "Vasospasm is excluded in this note."}, {"id": "d", "text": "Atherosclerosis is the most common cause listed."}, {"id": "e", "text": "Only congenital defects cause IHD in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Major causes listed are atherosclerosis (most common), coronary vasospasm, and thrombosis.', 'Ischemic Heart Disease - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Clinical spectrum. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Clinical spectrum. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Stable angina is the most severe endpoint in this note."}, {"id": "b", "text": "STEMI is unrelated to IHD spectrum in this note."}, {"id": "c", "text": "Unstable angina precedes infarction stages in spectrum."}, {"id": "d", "text": "NSTEMI and STEMI are part of IHD spectrum."}, {"id": "e", "text": "Silent ischemia can occur in this note."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: The IHD spectrum is silent ischemia to stable angina, unstable angina, NSTEMI, and STEMI.', 'Ischemic Heart Disease - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Risk factors from this note? (Select all that apply)', 'Which clues are consistent with Risk factors from this note? (Select all that apply)', '[{"id": "a", "text": "Smoking and obesity are listed risk factors."}, {"id": "b", "text": "Hypertension and diabetes are listed risk factors."}, {"id": "c", "text": "Only age under 30 is listed as risk in this note."}, {"id": "d", "text": "Family history does not matter in this note."}, {"id": "e", "text": "Age thresholds are listed for men and women."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Risk factors include HTN, diabetes, hyperlipidemia, smoking, obesity, family history, and age thresholds male >45/female >55.', 'Ischemic Heart Disease - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for LAD territory. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for LAD territory. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "LAD infarct primarily appears in II, III, aVF in this note."}, {"id": "b", "text": "LAD occlusion maps to V1–V4 anterior STEMI."}, {"id": "c", "text": "LAD is called widow maker in this note."}, {"id": "d", "text": "LAD mainly supplies inferior wall in this note."}, {"id": "e", "text": "Anterior territory loss risks LV failure."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: LAD supplies anterior wall and septum; occlusion causes anterior STEMI in V1–V4 and has high LV failure risk.', 'Ischemic Heart Disease - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and LCX territory, which statements are correct? (Select all that apply)', 'For suspected ACS and LCX territory, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Lateral MI leads include I, aVL, V5, V6 for LCX."}, {"id": "b", "text": "LCX can supply SA node in some patients."}, {"id": "c", "text": "LCX always supplies AV node in this note."}, {"id": "d", "text": "LCX infarct localizes to V1–V4 in this note."}, {"id": "e", "text": "LCX is often non-dominant in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: LCX supplies lateral wall (and SA node in some); occlusion causes lateral MI in I, aVL, V5–V6.', 'Ischemic Heart Disease - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support RCA territory? (Select all that apply)', 'During reassessment, which observations support RCA territory? (Select all that apply)', '[{"id": "a", "text": "RCA infarcts primarily produce lateral lead changes in this note."}, {"id": "b", "text": "AV block is rare with RCA MI in this note."}, {"id": "c", "text": "Inferior STEMI leads are II, III, aVF for RCA."}, {"id": "d", "text": "RCA supplies right ventricle/inferior wall in this note."}, {"id": "e", "text": "AV blocks are common with RCA MI in this note."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: RCA supplies right ventricle, inferior wall, and AV node in about 80%; occlusion causes inferior STEMI in II, III, aVF with AV blocks common.', 'Ischemic Heart Disease - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Stable angina pattern. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Stable angina pattern. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Rest commonly relieves symptoms."}, {"id": "b", "text": "Stable angina is predictable in this note."}, {"id": "c", "text": "Stable angina does not respond to rest in this note."}, {"id": "d", "text": "Stable angina usually occurs at rest for >20 min in this note."}, {"id": "e", "text": "Duration is usually under 5 minutes."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Stable angina is predictable with exertion/stress, lasts less than 5 minutes, and resolves with rest.', 'Ischemic Heart Disease - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Unstable angina pattern from this note? (Select all that apply)', 'Which clues are consistent with Unstable angina pattern from this note? (Select all that apply)', '[{"id": "a", "text": "Unstable angina may occur at rest."}, {"id": "b", "text": "Unstable angina is always exertional and brief in this note."}, {"id": "c", "text": "Duration over 20 minutes is noted."}, {"id": "d", "text": "Unstable angina is managed only with home rest in this note."}, {"id": "e", "text": "Early PCI strategy is listed for unstable angina."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Unstable angina is unpredictable, can occur at rest/minimal activity, often lasts >20 minutes, and does not resolve easily.', 'Ischemic Heart Disease - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for Variant angina. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for Variant angina. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Transient ST elevation is described."}, {"id": "b", "text": "CCBs and nitrates are listed therapy."}, {"id": "c", "text": "Beta-blockers are preferred first-line in this note."}, {"id": "d", "text": "Variant angina has permanent ST depression in this note."}, {"id": "e", "text": "Variant angina occurs at rest/night in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Prinzmetal angina is due to coronary vasospasm, occurs at rest/night, and shows transient ST elevation.', 'Ischemic Heart Disease - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and Stable angina treatment, which statements are correct? (Select all that apply)', 'For suspected ACS and Stable angina treatment, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Rest is first response in stable episodes."}, {"id": "b", "text": "Thrombolytics are routine first-line for stable angina in this note."}, {"id": "c", "text": "Stable angina treatment excludes aspirin in this note."}, {"id": "d", "text": "Beta-blockers and aspirin are listed in management."}, {"id": "e", "text": "SL nitroglycerin is listed for stable episodes."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Stable angina treatment includes rest, SL nitroglycerin, beta-blockers, and aspirin.', 'Ischemic Heart Disease - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Unstable angina treatment? (Select all that apply)', 'During reassessment, which observations support Unstable angina treatment? (Select all that apply)', '[{"id": "a", "text": "No antithrombotic therapy is used in this note."}, {"id": "b", "text": "Early PCI is part of management."}, {"id": "c", "text": "Dual antiplatelet and anticoagulation are listed."}, {"id": "d", "text": "Hospitalization is indicated in unstable angina."}, {"id": "e", "text": "Unstable angina should be managed only with PRN NTG at home in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Unstable angina management includes hospitalization, anticoagulation, dual antiplatelet therapy, and early PCI.', 'Ischemic Heart Disease - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around STEMI pathophysiology. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around STEMI pathophysiology. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "STEMI is subendocardial only in this note."}, {"id": "b", "text": "STEMI is partial occlusion without ST changes in this note."}, {"id": "c", "text": "STEMI is complete occlusion in this note."}, {"id": "d", "text": "Q waves may appear later in STEMI."}, {"id": "e", "text": "ST elevation is present in STEMI."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: STEMI is complete coronary occlusion with transmural infarction and ST elevation, with Q waves developing later.', 'Ischemic Heart Disease - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with STEMI reperfusion target from this note? (Select all that apply)', 'Which clues are consistent with STEMI reperfusion target from this note? (Select all that apply)', '[{"id": "a", "text": "Thrombolytic target is 30 minutes if PCI unavailable."}, {"id": "b", "text": "Reperfusion timing is urgent in STEMI."}, {"id": "c", "text": "STEMI PCI can wait 24 hours in this note."}, {"id": "d", "text": "Door-to-balloon target is 90 minutes in this note."}, {"id": "e", "text": "Thrombolytics are delayed until day 2 in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Primary PCI should occur within 90 minutes door-to-balloon; if unavailable, thrombolytics within 30 minutes are listed.', 'Ischemic Heart Disease - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for NSTEMI profile. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for NSTEMI profile. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "NSTEMI requires ST elevation to diagnose in this note."}, {"id": "b", "text": "ST depression/T-wave inversion can occur."}, {"id": "c", "text": "Troponin is elevated in NSTEMI."}, {"id": "d", "text": "NSTEMI has no ST elevation in this note."}, {"id": "e", "text": "NSTEMI troponin remains normal in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: NSTEMI is partial occlusion or severe vasospasm with subendocardial infarction, ST depression/T inversion, and elevated troponin without ST elevation.', 'Ischemic Heart Disease - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and NSTEMI timing, which statements are correct? (Select all that apply)', 'For suspected ACS and NSTEMI timing, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Dual antiplatelet is listed in NSTEMI care."}, {"id": "b", "text": "NSTEMI never receives PCI in this note."}, {"id": "c", "text": "Anticoagulation is listed in NSTEMI care."}, {"id": "d", "text": "Early PCI window is 24–72 hours in this note."}, {"id": "e", "text": "NSTEMI is treated with discharge only in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: NSTEMI treatment includes anticoagulation + dual antiplatelet and early PCI within 24–72 hours.', 'Ischemic Heart Disease - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support NTG BP safety? (Select all that apply)', 'During reassessment, which observations support NTG BP safety? (Select all that apply)', '[{"id": "a", "text": "Standing position is preferred for NTG in this note."}, {"id": "b", "text": "Patient should be seated before dosing."}, {"id": "c", "text": "NTG should be given regardless of BP in this note."}, {"id": "d", "text": "Hold NTG if systolic BP is under 90."}, {"id": "e", "text": "BP check is step 1 in protocol."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Before SL nitroglycerin, check BP and hold if systolic is <90 mmHg; patient should sit down.', 'Ischemic Heart Disease - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around NTG dosing sequence. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around NTG dosing sequence. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Maximum is 3 doses in protocol."}, {"id": "b", "text": "NTG should be repeated every 30 seconds in this note."}, {"id": "c", "text": "Persistent pain after sequential doses needs escalation."}, {"id": "d", "text": "Dosing interval is 5 minutes in this note."}, {"id": "e", "text": "Unlimited NTG doses are allowed in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: SL NTG is given every 5 minutes up to 3 doses for persistent angina.', 'Ischemic Heart Disease - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with NTG escalation from this note? (Select all that apply)', 'Which clues are consistent with NTG escalation from this note? (Select all that apply)', '[{"id": "a", "text": "Persistent pain indicates possible acute MI."}, {"id": "b", "text": "Escalation should not be delayed."}, {"id": "c", "text": "Wait several hours after 3 doses before escalation in this note."}, {"id": "d", "text": "Pain persistence after 3 doses is low concern in this note."}, {"id": "e", "text": "Emergency activation follows 3 unrelieved doses."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: If pain remains after 3 doses, activate emergency response (call 911/STEMI protocol).', 'Ischemic Heart Disease - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being assessed for NTG storage. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being assessed for NTG storage. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "NTG should be stored in clear pill organizers in this note."}, {"id": "b", "text": "Loss of tongue burning suggests potency loss."}, {"id": "c", "text": "Potency is unaffected by storage in this note."}, {"id": "d", "text": "Replace every 6 months is listed."}, {"id": "e", "text": "Dark glass bottle storage is specified."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: NTG should be kept in original dark glass bottle, room temperature, replaced every 6 months or when tongue burning sensation disappears.', 'Ischemic Heart Disease - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected ACS and MONA oxygen rule, which statements are correct? (Select all that apply)', 'For suspected ACS and MONA oxygen rule, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Oxygen is part of MONA with indication limits."}, {"id": "b", "text": "Hyperoxia avoidance is emphasized."}, {"id": "c", "text": "All chest pain patients need routine oxygen regardless of saturation in this note."}, {"id": "d", "text": "Oxygen is conditional on SpO2 <94% in this note."}, {"id": "e", "text": "Oxygen is never used in ACS in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Oxygen in MONA is indicated only if SpO2 is below 94% to avoid hyperoxia.', 'Ischemic Heart Disease - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support MONA aspirin detail? (Select all that apply)', 'During reassessment, which observations support MONA aspirin detail? (Select all that apply)', '[{"id": "a", "text": "Dose listed is 325 mg."}, {"id": "b", "text": "Aspirin is part of first-line acute MI response."}, {"id": "c", "text": "Aspirin should be swallowed whole and delayed in this note."}, {"id": "d", "text": "Aspirin should be chewed immediately."}, {"id": "e", "text": "Aspirin is contraindicated in all ACS cases in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Aspirin 325 mg is given immediately and chewed.', 'Ischemic Heart Disease - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Additional ACS medications. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Additional ACS medications. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Heparin is avoided in all ACS in this note."}, {"id": "b", "text": "Clopidogrel + aspirin is listed."}, {"id": "c", "text": "ACE inhibitor and statin are listed post-MI supports."}, {"id": "d", "text": "Statins are not part of post-MI care in this note."}, {"id": "e", "text": "Heparin is listed for anticoagulation."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Additional therapies listed are DAPT (clopidogrel + aspirin), heparin, beta-blocker, ACE inhibitor, and statin.', 'Ischemic Heart Disease - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Troponin I kinetics from this note? (Select all that apply)', 'Which clues are consistent with Troponin I kinetics from this note? (Select all that apply)', '[{"id": "a", "text": "Troponin I rises at 3–6 hours."}, {"id": "b", "text": "Troponin I normalizes within 12 hours in this note."}, {"id": "c", "text": "Troponin I may remain elevated for 7–10 days."}, {"id": "d", "text": "Troponin I normal is >5 ng/mL in this note."}, {"id": "e", "text": "Troponin I peaks around 12–24 hours."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Troponin I normal is <0.04 ng/mL, rises 3–6 hrs, peaks 12–24 hrs, and remains elevated 7–10 days.', 'Ischemic Heart Disease - NCLEX', true, 100, 1, true);
